// PM2 Ecosystem — Sanad Legal Dashboard
//
// Usage:
//   pm2 start ecosystem.config.cjs --env production
//   pm2 save
//   pm2 startup
//   pm2 logs sanad
//   pm2 restart sanad
//   pm2 stop sanad

const path = require('path')
const PROJECT_DIR = __dirname

module.exports = {
  apps: [
    {
      name: 'sanad',
      script: '.next/standalone/server.js',
      cwd: PROJECT_DIR,
      instances: 1, // SQLite — single instance only
      exec_mode: 'fork',
      autorestart: true,
      max_restarts: 10,
      restart_delay: 3000,
      max_memory_restart: '500M',
      env: {
        NODE_ENV: 'production',
        PORT: process.env.PORT || 3001,
        NEXT_TELEMETRY_DISABLED: 1,
        DATABASE_URL: `file:${path.join(PROJECT_DIR, 'db/custom.db')}`,
      },
      env_production: {
        NODE_ENV: 'production',
      },
      error_file: path.join(PROJECT_DIR, 'logs/sanad-error.log'),
      out_file: path.join(PROJECT_DIR, 'logs/sanad-out.log'),
      log_date_format: 'YYYY-MM-DD HH:mm:ss Z',
      merge_logs: true,
      watch: false,
    },
  ],
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import { useTheme } from 'next-themes'
import { Moon, Sun, RefreshCw, Languages, GraduationCap, Briefcase, Search } from 'lucide-react'
import { Button } from '@/components/ui/button'
import { Toaster as SonnerToaster } from '@/components/ui/sonner'
import { useLang } from '@/lib/sanad/i18n'
import { DashboardView } from '@/components/sanad/DashboardView'
import { ComplianceView } from '@/components/sanad/ComplianceView'
import { CasesView } from '@/components/sanad/CasesView'
import { DeepWorkView } from '@/components/sanad/DeepWorkView'
import { TasksView } from '@/components/sanad/TasksView'
import { DocumentsView } from '@/components/sanad/DocumentsView'
import { ClientsView } from '@/components/sanad/ClientsView'
import { InvoicesView } from '@/components/sanad/InvoicesView'
import { ScannerView } from '@/components/sanad/ScannerView'
import { CalendarView } from '@/components/sanad/CalendarView'
import { CommunicationsView } from '@/components/sanad/CommunicationsView'
import { StudentView } from '@/components/sanad/StudentView'
import { TodayFocusView } from '@/components/sanad/TodayFocusView'
import { CommandPalette } from '@/components/sanad/CommandPalette'
import { TopNav } from '@/components/sanad/TopNav'
import { MobileNav } from '@/components/sanad/MobileNav'
import { Sidebar } from '@/components/sanad/Sidebar'
import type { DashboardData, StudentDashboardData } from '@/lib/sanad/types'

type View = 'today' | 'dashboard' | 'compliance' | 'cases' | 'deepwork' | 'tasks' | 'documents' | 'clients' | 'invoices' | 'scanner' | 'calendar' | 'communications'
type Persona = 'lawyer' | 'student'

import { useQuery } from '@tanstack/react-query'
import { getLawyerDashboard } from '@/app/actions/dashboard'
import { getStudentDashboard } from '@/app/actions/studentDashboard'

const PERSONA_STORAGE_KEY = 'sanad.persona'

export default function Home() {
  const { lang, t, toggle: toggleLang } = useLang()
  const [persona, setPersona] = useState<Persona>('lawyer')
  const [view, setView] = useState<string>('today')
  const { theme, setTheme } = useTheme()
  const [mounted, setMounted] = useState(false)
  const [paletteOpen, setPaletteOpen] = useState(false)

  const { data: dashboardData, isLoading: isLoadingLawyer, refetch: refetchLawyer, isRefetching: isRefetchingLawyer } = useQuery<DashboardData>({
    queryKey: ['dashboard', 'lawyer'],
    queryFn: async () => {
      // Use Server Action instead of fetch
      return await getLawyerDashboard() as unknown as DashboardData
    },
    enabled: persona === 'lawyer',
  })

  const { data: studentDashboardData, isLoading: isLoadingStudent, refetch: refetchStudent, isRefetching: isRefetchingStudent } = useQuery<StudentDashboardData>({
    queryKey: ['dashboard', 'student'],
    queryFn: async () => {
      // Use Server Action instead of fetch
      return await getStudentDashboard() as unknown as StudentDashboardData
    },
    enabled: persona === 'student',
  })

  const data = dashboardData || null
  const studentData = studentDashboardData || null
  const loading = persona === 'lawyer' ? isLoadingLawyer || isRefetchingLawyer : isLoadingStudent || isRefetchingStudent

  const onRefresh = () => {
    if (persona === 'lawyer') refetchLawyer()
    else refetchStudent()
  }

  const onChange = onRefresh

  useEffect(() => { setMounted(true) }, [])

  useEffect(() => {
    const saved = typeof window !== 'undefined' ? localStorage.getItem(PERSONA_STORAGE_KEY) : null
    if (saved === 'student' || saved === 'lawyer') setPersona(saved)
  }, [])

  useEffect(() => {
    if (process.env.NODE_ENV === 'production') {
      if ('serviceWorker' in navigator) {
        navigator.serviceWorker.register('/sw.js').catch(() => {})
      }
    } else {
      if ('serviceWorker' in navigator) {
        navigator.serviceWorker.getRegistrations().then((registrations) => {
          for (const registration of registrations) {
            registration.unregister().then((success) => {
              if (success) {
                console.log('Unregistered active service worker in development mode')
                window.location.reload()
              }
            })
          }
        })
      }
    }
  }, [])

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault()
        setPaletteOpen((o) => !o)
      }
    }
    document.addEventListener('keydown', handler)
    return () => document.removeEventListener('keydown', handler)
  }, [])

  useEffect(() => {
    if (!data) return
    const overdue = (data.stats?.overdueTasks || 0) + (data.stats?.outstandingInvoices || 0)
    const baseTitle = 'سند — لوحة العمليات اليومية'
    document.title = overdue > 0 ? `(${overdue}) ${baseTitle}` : baseTitle
  }, [data])

  const switchPersona = (p: Persona) => {
    setPersona(p)
    localStorage.setItem(PERSONA_STORAGE_KEY, p)
    setView('today')
  }

  const now = new Date()
  const timeLocale = lang === 'ar' ? 'ar-SA' : 'en-GB'
  const timeStr = now.toLocaleTimeString(timeLocale, { hour: '2-digit', minute: '2-digit' })
  const dateStr = now.toLocaleDateString(timeLocale, { weekday: 'short', day: 'numeric', month: 'short' })

  return (
    <div className="min-h-screen flex flex-col bg-background relative overflow-hidden" dir={lang === 'ar' ? 'rtl' : 'ltr'}>
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-emerald-600/10 rounded-full blur-[120px] pointer-events-none" />
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-600/10 rounded-full blur-[120px] pointer-events-none" />
      <div className="absolute inset-0 bg-grid-white/[0.02] bg-[size:32px] pointer-events-none" />

      <div className="relative z-10 flex flex-col min-h-screen w-full">
      <SonnerToaster position="top-right" richColors closeButton />

      <TopNav
        persona={persona}
        switchPersona={switchPersona}
        loading={loading}
        onRefresh={onRefresh}
        setPaletteOpen={setPaletteOpen}
        mounted={mounted}
      />

      <MobileNav persona={persona} view={view} setView={setView} />

      <div className="flex flex-1 mx-auto max-w-7xl w-full px-4 sm:px-6 lg:px-8 py-6 gap-6">
        <Sidebar persona={persona} view={view} setView={setView} data={data} />

        <main className="flex-1 min-w-0">
          {loading && (!data || (persona === 'student' && !studentData)) ? (
            <div className="space-y-4 animate-pulse">
              <div className="h-8 w-48 bg-muted rounded" />
              <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">{[1, 2, 3, 4].map((i) => <div key={i} className="h-20 bg-muted rounded-lg" />)}</div>
              <div className="h-64 bg-muted rounded-lg" />
            </div>
          ) : persona === 'student' && studentData ? (
            <StudentView data={studentData} onChange={onChange} />
          ) : data ? (
            <>
              {view === 'today' && <TodayFocusView data={data} onNavigate={(v) => setView(v)} onStartFocus={() => setView('deepwork')} />}
              {view === 'dashboard' && <DashboardView data={data} onNavigate={(v) => setView(v)} />}
              {view === 'compliance' && <ComplianceView items={data.compliance.all} onChange={onChange} />}
              {view === 'cases' && <CasesView cases={data.cases.all} clients={data.clients} onChange={onChange} />}
              {view === 'deepwork' && <DeepWorkView cases={data.cases.all} timeEntries={data.timeEntries} onChange={onChange} />}
              {view === 'tasks' && <TasksView tasks={data.tasks.all} cases={data.cases.all} onChange={onChange} />}
              {view === 'documents' && <DocumentsView documents={data.documents.all} cases={data.cases.all} onChange={onChange} />}
              {view === 'clients' && <ClientsView clients={data.clients} onChange={onChange} />}
              {view === 'invoices' && <InvoicesView invoices={data.invoices} clients={data.clients} cases={data.cases.all} timeEntries={data.timeEntries.filter((te: any) => te.billable && !te.invoiced)} stats={data.stats} onChange={onChange} />}
              {view === 'scanner' && <ScannerView />}
              {view === 'calendar' && <CalendarView onNavigate={(v) => setView(v)} />}
              {view === 'communications' && <CommunicationsView cases={data.cases.all} clients={data.clients} onChange={onChange} />}
            </>
          ) : (
            <div className="text-center py-12 text-sm text-muted-foreground">{t('dash.failed_load')} <Button variant="link" onClick={() => onChange()}>{t('dash.retry')}</Button></div>
          )}
        </main>
      </div>

      <footer className="mt-auto border-t border-border bg-background">
        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-3">
          <div className="flex flex-col sm:flex-row items-center justify-between gap-2 text-xs text-muted-foreground">
            <p>{t('common.footer_left')}</p>
            <p className="flex items-center gap-2"><span className="inline-block h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse" />{t('common.footer_right')}</p>
          </div>
        </div>
      </footer>

      {mounted && <CommandPalette open={paletteOpen} onOpenChange={setPaletteOpen} onNavigate={(v) => setView(v)} onCreate={() => {}} />}
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
} from '@/components/ui/sheet'
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { ScrollArea } from '@/components/ui/scroll-area'
import { Separator } from '@/components/ui/separator'
import { Skeleton } from '@/components/ui/skeleton'
import { Checkbox } from '@/components/ui/checkbox'
import {
  Gavel,
  User,
  Calendar,
  CalendarClock,
  FileText,
  Clock,
  MessageSquare,
  Receipt,
  CheckCircle2,
  AlertTriangle,
  Scale,
  Briefcase,
  Phone,
  Mail,
  Users,
  StickyNote,
  ArrowDownLeft,
  ArrowUpRight,
  Sparkles,
  Bot,
  ShieldAlert,
  type LucideIcon,
} from 'lucide-react'
import { toast } from 'sonner'
import { useLang } from '@/lib/sanad/i18n'
import {
  formatDate,
  formatDuration,
  formatSAR,
  daysUntil,
  PRIORITY_COLORS,
  DOC_STATUS_COLORS,
  type Client,
  type Task,
  type TimeEntry,
  type Communication,
  type Invoice,
  type LegalDocument,
} from '@/lib/sanad/types'

interface Props {
  caseId: string | null
  onClose: () => void
  onChange: () => void
}

/** Full case detail payload returned by GET /api/cases/[id]/detail */
interface CaseDetail {
  id: string
  title: string
  clientId: string | null
  clientName: string
  caseType: string
  stage: string
  priority: string
  dueDate: string | null
  hearingDate: string | null
  value: number | null
  caseNumber: string | null
  court: string | null
  opposingParty: string | null
  notes: string | null
  client: Client | null
  timeEntries: (TimeEntry & { invoice?: { id: string; number: string } | null })[]
  communications: (Communication & { client?: { name: string } | null })[]
  invoices: Invoice[]
  tasks: Task[]
  documents: LegalDocument[]
  stats: {
    billableSec: number
    billableSAR: number
    uninvoicedSAR: number
    invoicedSAR: number
    totalCommunications: number
    totalInvoices: number
    openTasks: number
  }
}

// ---- Display color maps ----

const STAGE_COLORS: Record<string, string> = {
  drafting: 'bg-amber-100 text-amber-800 dark:bg-amber-900/40 dark:text-amber-200',
  client_review: 'bg-purple-100 text-purple-800 dark:bg-purple-900/40 dark:text-purple-200',
  filed: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200',
  closed: 'bg-muted text-muted-foreground',
}

const INVOICE_STATUS_COLORS: Record<string, string> = {
  draft: 'bg-muted text-muted-foreground',
  sent: 'bg-amber-100 text-amber-800 dark:bg-amber-900/40 dark:text-amber-200',
  paid: 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/40 dark:text-emerald-200',
  overdue: 'bg-rose-100 text-rose-800 dark:bg-rose-900/40 dark:text-rose-200',
  cancelled: 'bg-slate-100 text-slate-800 dark:bg-slate-900/40 dark:text-slate-200',
}

const COMM_TYPE_META: Record<string, { Icon: LucideIcon; color: string }> = {
  call: { Icon: Phone, color: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-300' },
  email: { Icon: Mail, color: 'bg-purple-100 text-purple-700 dark:bg-purple-900/40 dark:text-purple-300' },
  meeting: { Icon: Users, color: 'bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-300' },
  sms: { Icon: MessageSquare, color: 'bg-cyan-100 text-cyan-700 dark:bg-cyan-900/40 dark:text-cyan-300' },
  note: { Icon: StickyNote, color: 'bg-slate-100 text-slate-700 dark:bg-slate-900/40 dark:text-slate-300' },
}

function getCommMeta(type: string) {
  return COMM_TYPE_META[type] ?? COMM_TYPE_META.note
}

const DIRECTION_META: Record<string, { Icon: LucideIcon; color: string }> = {
  incoming: { Icon: ArrowDownLeft, color: 'text-emerald-600 dark:text-emerald-400' },
  outgoing: { Icon: ArrowUpRight, color: 'text-amber-600 dark:text-amber-400' },
}

function getDirectionMeta(direction: string) {
  return DIRECTION_META[direction] ?? DIRECTION_META.outgoing
}

// ---- Helpers ----

/** Compute SAR amount for a single time entry. */
function entryAmount(e: TimeEntry): number {
  if (!e.hourlyRate) return 0
  return (e.hourlyRate * e.durationSec) / 3600
}

// =====================================================================
// Main drawer
// =====================================================================

export function CaseDetailDrawer({ caseId, onClose, onChange }: Props) {
  const { lang, t } = useLang()
  const [data, setData] = useState<CaseDetail | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  // Drawer slides in from the "start" side: right in RTL (Arabic), left in LTR (English).
  const side: 'left' | 'right' = lang === 'ar' ? 'right' : 'left'

  // Fetch case detail whenever caseId changes. We keep the cancelled-flag
  // pattern to avoid setState-after-unmount warnings.
  useEffect(() => {
    if (!caseId) {
      setLoading(false)
      setError(null)
      return // keep stale data so the close animation is smooth
    }
    let cancelled = false
    setLoading(true)
    setError(null)
    fetch(`/api/cases/${caseId}/detail`)
      .then(async (r) => {
        if (!r.ok) throw new Error(r.status === 404 ? 'Case not found' : 'Failed to load case')
        return r.json() as Promise<CaseDetail>
      })
      .then((d) => {
        if (cancelled) return
        setData(d)
        setLoading(false)
      })
      .catch((e) => {
        if (cancelled) return
        setError(e instanceof Error ? e.message : 'Failed to load case')
        setLoading(false)
      })
    return () => {
      cancelled = true
    }
  }, [caseId])

  const handleOpenChange = (open: boolean) => {
    if (!open) onClose()
  }

  // Toggle a task's done state with optimistic update + revert-on-error.
  const toggleTask = async (task: Task) => {
    const newStatus = task.status === 'done' ? 'todo' : 'done'
    setData((prev) =>
      prev
        ? {
            ...prev,
            tasks: prev.tasks.map((tk) => (tk.id === task.id ? { ...tk, status: newStatus } : tk)),
            stats: {
              ...prev.stats,
              openTasks: Math.max(0, prev.stats.openTasks + (newStatus === 'done' ? -1 : 1)),
            },
          }
        : prev,
    )
    try {
      const r = await fetch(`/api/tasks/${task.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: newStatus }),
      })
      if (!r.ok) throw new Error('Failed to update task')
      toast.success(newStatus === 'done' ? t('tasks.completed') : t('tasks.reopened'))
      onChange()
    } catch {
      // Revert optimistic update
      setData((prev) =>
        prev
          ? {
              ...prev,
              tasks: prev.tasks.map((tk) => (tk.id === task.id ? { ...tk, status: task.status } : tk)),
              stats: {
                ...prev.stats,
                openTasks: Math.max(0, prev.stats.openTasks + (newStatus === 'done' ? 1 : -1)),
              },
            }
          : prev,
      )
      toast.error('Failed to update task')
    }
  }

  const showBody = data && !error

  return (
    <Sheet open={caseId !== null} onOpenChange={handleOpenChange}>
      <SheetContent
        side={side}
        className="w-full sm:max-w-2xl gap-0 p-0 flex flex-col"
      >
        {/* ---------- Header ---------- */}
        <SheetHeader className="p-5 border-b border-border gap-2 space-y-0">
          <SheetDescription className="sr-only">{t('case.detail')}</SheetDescription>

          {data && !loading ? (
            <>
              <p className="text-xs font-medium text-muted-foreground flex items-center gap-1.5">
                <Gavel className="size-3.5" />
                {t('case.detail')}
              </p>
              <SheetTitle className="text-xl font-bold leading-tight text-start">
                {data.title}
              </SheetTitle>
              <div className="flex flex-wrap items-center gap-1.5 pt-0.5">
                <Badge
                  variant="outline"
                  className={`text-[10px] px-1.5 py-0 ${STAGE_COLORS[data.stage] ?? STAGE_COLORS.closed}`}
                >
                  {t(`stage.${data.stage}`)}
                </Badge>
                <Badge
                  variant="outline"
                  className={`text-[10px] px-1.5 py-0 ${
                    PRIORITY_COLORS[data.priority]?.color ?? PRIORITY_COLORS.normal.color
                  }`}
                >
                  {t(`prio.${data.priority}`)}
                </Badge>
                <Badge variant="outline" className="text-[10px] px-1.5 py-0 bg-muted/60">
                  {t(`ctype.${data.caseType}`)}
                </Badge>
              </div>
            </>
          ) : loading ? (
            <>
              <p className="text-xs font-medium text-muted-foreground flex items-center gap-1.5">
                <Gavel className="size-3.5" />
                {t('case.detail')}
              </p>
              <SheetTitle className="text-xl font-bold leading-tight text-start">
                <Skeleton className="h-6 w-3/4" />
              </SheetTitle>
              <div className="flex gap-1.5 pt-0.5">
                <Skeleton className="h-5 w-20" />
                <Skeleton className="h-5 w-20" />
                <Skeleton className="h-5 w-20" />
              </div>
            </>
          ) : error ? (
            <>
              <p className="text-xs font-medium text-muted-foreground flex items-center gap-1.5">
                <Gavel className="size-3.5" />
                {t('case.detail')}
              </p>
              <SheetTitle className="text-base font-semibold text-rose-600 dark:text-rose-400 flex items-center gap-2">
                <AlertTriangle className="size-4" />
                {error}
              </SheetTitle>
            </>
          ) : (
            <SheetTitle className="text-base font-semibold">{t('case.detail')}</SheetTitle>
          )}
        </SheetHeader>

        {/* ---------- Body ---------- */}
        {showBody && data ? (
          <Tabs defaultValue="overview" className="flex-1 flex flex-col min-h-0 gap-0" dir={lang === 'ar' ? 'rtl' : 'ltr'}>
            <div className="border-b border-border px-2 shrink-0">
              <TabsList className="bg-transparent h-auto p-1 w-full justify-start overflow-x-auto rounded-none">
                <TabsTrigger value="overview" className="flex-none">
                  {t('case.overview')}
                </TabsTrigger>
                <TabsTrigger value="tasks" className="flex-none gap-1.5">
                  {t('case.tasks')}
                  {data.stats.openTasks > 0 && (
                    <span className="inline-flex items-center justify-center min-w-4 h-4 rounded-full bg-primary/15 text-primary text-[10px] px-1 leading-none">
                      {data.stats.openTasks.toLocaleString(lang === 'ar' ? 'ar-EG' : 'en-US')}
                    </span>
                  )}
                </TabsTrigger>
                <TabsTrigger value="documents" className="flex-none gap-1.5">
                  {t('case.documents')}
                  {data.documents.length > 0 && (
                    <CountChip n={data.documents.length} lang={lang} />
                  )}
                </TabsTrigger>
                <TabsTrigger value="time" className="flex-none gap-1.5">
                  {t('case.time_entries')}
                  {data.timeEntries.length > 0 && (
                    <CountChip n={data.timeEntries.length} lang={lang} />
                  )}
                </TabsTrigger>
                <TabsTrigger value="comms" className="flex-none gap-1.5">
                  {t('case.communications')}
                  {data.communications.length > 0 && (
                    <CountChip n={data.communications.length} lang={lang} />
                  )}
                </TabsTrigger>
                <TabsTrigger value="invoices" className="flex-none gap-1.5">
                  {t('case.invoices')}
                  {data.invoices.length > 0 && (
                    <CountChip n={data.invoices.length} lang={lang} />
                  )}
                </TabsTrigger>
                <TabsTrigger value="ai" className="flex-none gap-1.5">
                  <Sparkles className="size-3.5 text-amber-500" />
                  {t('case.ai_insights')}
                </TabsTrigger>
              </TabsList>
            </div>

            <TabsContent value="overview" className="flex-1 min-h-0 outline-none">
              <ScrollArea className="h-full">
                <OverviewTab data={data} />
              </ScrollArea>
            </TabsContent>

            <TabsContent value="tasks" className="flex-1 min-h-0 outline-none">
              <ScrollArea className="h-full">
                <TasksTab tasks={data.tasks} onToggle={toggleTask} />
              </ScrollArea>
            </TabsContent>

            <TabsContent value="documents" className="flex-1 min-h-0 outline-none">
              <ScrollArea className="h-full">
                <DocumentsTab documents={data.documents} />
              </ScrollArea>
            </TabsContent>

            <TabsContent value="time" className="flex-1 min-h-0 outline-none">
              <ScrollArea className="h-full">
                <TimeTab timeEntries={data.timeEntries} />
              </ScrollArea>
            </TabsContent>

            <TabsContent value="comms" className="flex-1 min-h-0 outline-none">
              <ScrollArea className="h-full">
                <CommsTab communications={data.communications} />
              </ScrollArea>
            </TabsContent>

            <TabsContent value="invoices" className="flex-1 min-h-0 outline-none">
              <ScrollArea className="h-full">
                <InvoicesTab invoices={data.invoices} />
              </ScrollArea>
            </TabsContent>

            <TabsContent value="ai" className="flex-1 min-h-0 outline-none">
              <ScrollArea className="h-full">
                <AiInsightsTab data={data} />
              </ScrollArea>
            </TabsContent>
          </Tabs>
        ) : (
          loading && (
            <div className="flex-1 p-5 space-y-3 overflow-hidden">
              <Skeleton className="h-28 w-full rounded-lg" />
              <Skeleton className="h-28 w-full rounded-lg" />
              <Skeleton className="h-28 w-full rounded-lg" />
            </div>
          )
        )}

        {/* ---------- Footer ---------- */}
        <SheetFooter className="border-t border-border p-3 flex-row justify-end gap-2 mt-auto">
          <Button variant="outline" size="sm" onClick={onClose}>
            {t('case.close')}
          </Button>
        </SheetFooter>
      </SheetContent>
    </Sheet>
  )
}

