            </div>

            <div className="space-y-1.5">
              <Label className="text-xs">{lang === 'ar' ? 'الموضوع *' : 'Subject *'}</Label>
              <Input
                value={form.subject}
                onChange={(e) => setForm({ ...form, subject: e.target.value })}
                placeholder={lang === 'ar' ? 'مثال: مناقشة بنود العقد' : 'e.g., Discussed contract terms'}
                className="h-8"
