                  <SelectContent>
                    <SelectItem value="">{lang === 'ar' ? 'بدون عميل' : 'No client'}</SelectItem>
                    {clients.map((c) => <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>)}
