              </div>
              <div className="space-y-1.5">
                <Label className="text-xs">{lang === 'ar' ? 'القضية' : 'Case'}</Label>
                <Select value={form.caseId} onValueChange={(v) => setForm({ ...form, caseId: v })}>
                  <SelectTrigger className="h-8 text-xs"><SelectValue placeholder={lang === 'ar' ? 'اختر قضية' : 'Select case'} /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value="">{lang === 'ar' ? 'بدون قضية' : 'No case'}</SelectItem>
                    {cases.filter((c) => c.stage !== 'closed').map((c) => <SelectItem key={c.id} value={c.id}>{c.title}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
              {(form.type === 'call' || form.type === 'meeting') && (
                <div className="space-y-1.5">
                  <Label className="text-xs">{lang === 'ar' ? 'المدة (دقيقة)' : 'Duration (min)'}</Label>
                  <Input
                    type="number"
                    min="1"
                    value={form.durationMin}
                    onChange={(e) => setForm({ ...form, durationMin: e.target.value })}
                    placeholder="30"
                    className="h-8"
                  />
                </div>
              )}
            </div>

            <div className="space-y-1.5">
              <Label className="text-xs">{lang === 'ar' ? 'ملاحظات / ملخص' : 'Notes / Summary'}</Label>
              <Textarea
                value={form.body}
                onChange={(e) => setForm({ ...form, body: e.target.value })}
                placeholder={lang === 'ar' ? 'ملخص ما تمت مناقشته أو نتائج التواصل...' : 'Summary of what was discussed or outcome...'}
                rows={3}
                className="text-sm"
              />
            </div>

            <div className="flex justify-end gap-2">
              <Button variant="outline" size="sm" onClick={() => setShowForm(false)}>{lang === 'ar' ? 'إلغاء' : 'Cancel'}</Button>
              <Button size="sm" onClick={save} disabled={saving}>
                {saving ? <Loader2 className="h-3.5 w-3.5 animate-spin mx-1" /> : null}
                {lang === 'ar' ? 'حفظ السجل' : 'Save Log'}
              </Button>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Filters */}
      <div className="flex flex-wrap items-center gap-2">
        <Filter className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
        <Input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder={lang === 'ar' ? 'بحث...' : 'Search...'}
          className="h-7 w-40 text-xs"
        />
        {(['all', 'call', 'email', 'meeting', 'sms', 'note'] as const).map((type) => (
          <button
            key={type}
            onClick={() => setFilterType(type)}
            className={`text-xs px-2 py-0.5 rounded-full border transition-colors ${
              filterType === type
                ? 'bg-primary text-primary-foreground border-primary'
                : 'border-border text-muted-foreground hover:border-primary/40'
            }`}
          >
            {type === 'all' ? (lang === 'ar' ? 'الكل' : 'All') : typeLabel(type)}
          </button>
        ))}
        <Separator orientation="vertical" className="h-4" />
        {(['all', 'incoming', 'outgoing'] as const).map((dir) => (
          <button
            key={dir}
            onClick={() => setFilterDirection(dir)}
            className={`text-xs px-2 py-0.5 rounded-full border transition-colors ${
              filterDirection === dir
                ? 'bg-primary text-primary-foreground border-primary'
                : 'border-border text-muted-foreground hover:border-primary/40'
            }`}
          >
            {dir === 'all' ? (lang === 'ar' ? 'الكل' : 'All') : dirLabel(dir)}
          </button>
        ))}
        {filtered.length !== items.length && (
          <span className="text-[10px] text-muted-foreground ms-1">
            {filtered.length} / {items.length}
          </span>
        )}
      </div>

      {/* List */}
      <Card>
        <CardContent className="p-0">
          {loading ? (
            <div className="py-12 flex justify-center">
              <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
            </div>
          ) : filtered.length === 0 ? (
            <div className="py-12 text-center text-sm text-muted-foreground">
              <Phone className="h-8 w-8 mx-auto mb-2 opacity-30" />
              {lang === 'ar' ? 'لا توجد سجلات تواصل' : 'No communications logged yet'}
            </div>
          ) : (
            <ScrollArea className="h-[520px]">
              <ul className="divide-y divide-border">
                {filtered.map((c) => {
                  const Icon = TYPE_ICONS[c.type] ?? FileText
                  const isIncoming = c.direction === 'incoming'
                  return (
                    <li key={c.id} className="px-4 py-3 hover:bg-muted/40 transition-colors">
                      <div className="flex items-start gap-3">
                        {/* Type icon */}
                        <div className={`mt-0.5 p-1.5 rounded-md shrink-0 ${TYPE_COLORS[c.type] || 'bg-muted text-muted-foreground'}`}>
                          <Icon className="h-3.5 w-3.5" />
                        </div>

                        <div className="flex-1 min-w-0">
                          {/* Subject + direction */}
                          <div className="flex items-center gap-2 flex-wrap">
                            <p className="text-sm font-medium leading-tight">{c.subject}</p>
                            <span className={`flex items-center gap-0.5 text-[10px] font-medium ${isIncoming ? 'text-blue-600 dark:text-blue-400' : 'text-emerald-600 dark:text-emerald-400'}`}>
                              {isIncoming
                                ? <ArrowDownLeft className="h-2.5 w-2.5" />
                                : <ArrowUpRight className="h-2.5 w-2.5" />}
                              {dirLabel(c.direction)}
                            </span>
                          </div>

                          {/* Body */}
                          {c.body && (
                            <p className="text-xs text-muted-foreground mt-0.5 line-clamp-2 leading-relaxed">{c.body}</p>
                          )}

                          {/* Meta row */}
                          <div className="flex items-center gap-2 mt-1.5 flex-wrap">
                            <Badge variant="outline" className={`text-[10px] px-1.5 py-0 ${TYPE_COLORS[c.type] || ''}`}>
                              {typeLabel(c.type)}
                            </Badge>
                            {c.client && (
                              <span className="text-[10px] text-muted-foreground">{c.client.name}</span>
                            )}
                            {c.case && (
                              <span className="text-[10px] text-muted-foreground truncate max-w-[180px]">{c.case.title}</span>
                            )}
                            {c.durationMin && (
                              <span className="text-[10px] text-muted-foreground flex items-center gap-0.5">
                                <Clock className="h-2.5 w-2.5" />
                                {c.durationMin}{lang === 'ar' ? 'د' : 'm'}
                              </span>
                            )}
                            <span className="text-[10px] text-muted-foreground ms-auto">{formatDate(c.date, lang)}</span>
                          </div>
                        </div>
                      </div>
                    </li>
                  )
                })}
              </ul>
            </ScrollArea>
          )}
        </CardContent>
      </Card>
    </div>
  )
}

'use client'

import { useEffect, useRef, useState, useMemo } from 'react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Separator } from '@/components/ui/separator'
import { ScrollArea } from '@/components/ui/scroll-area'
import {
  Pause,
  Play,
  Square,
  Timer as TimerIcon,
  Clock,
  Coffee,
  TrendingUp,
  DollarSign,
  Brain,
  History,
  BarChart2,
} from 'lucide-react'
import {
  ResponsiveContainer,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
} from 'recharts'
import { toast } from 'sonner'
import { useLang } from '@/lib/sanad/i18n'
import {
  formatDate,
  formatDuration,
  formatSAR,
  type LegalCase,
  type TimeEntry,
} from '@/lib/sanad/types'

interface Props {
  cases: LegalCase[]
  timeEntries: TimeEntry[]
  onChange: () => void
}

const STORAGE_KEY = 'sanad.timer.state.v1'

interface TimerState {
  mode: 'focus' | 'billable' | 'break'
  remaining: number
  total: number
  running: boolean
  startedAt: number | null
  description: string
  caseId: string | null
  hourlyRate: number
}

const DEFAULT_STATE: TimerState = {
  mode: 'focus',
  remaining: 25 * 60,
  total: 25 * 60,
  running: false,
  startedAt: null,
  description: '',
  caseId: null,
  hourlyRate: 850,
}

function loadState(): TimerState {
  if (typeof window === 'undefined') return DEFAULT_STATE
  try {
    const raw = localStorage.getItem(STORAGE_KEY)
    if (!raw) return DEFAULT_STATE
    const parsed = JSON.parse(raw) as TimerState
    if (parsed.running && parsed.startedAt) {
      const elapsed = Math.floor((Date.now() - parsed.startedAt) / 1000)
      const left = parsed.total - elapsed
      if (left <= 0) return { ...DEFAULT_STATE }
      return { ...parsed, remaining: left }
    }
    return parsed
  } catch {
    return DEFAULT_STATE
  }
}

export function DeepWorkView({ cases, timeEntries, onChange }: Props) {
  const { lang, t } = useLang()
  const [state, setState] = useState<TimerState>(DEFAULT_STATE)
  const [now, setNow] = useState(Date.now())
  const intervalRef = useRef<NodeJS.Timeout | null>(null)

  useEffect(() => { setState(loadState()) }, [])
  useEffect(() => { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)) }, [state])

  useEffect(() => {
    if (state.running) {
      intervalRef.current = setInterval(() => setNow(Date.now()), 250)
    } else if (intervalRef.current) {
      clearInterval(intervalRef.current)
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current) }
  }, [state.running])

  const elapsedSec = state.running && state.startedAt ? Math.floor((now - state.startedAt) / 1000) : 0
  const displaySec = state.running ? Math.max(0, state.total - elapsedSec) : state.remaining
  const progressPct = state.total > 0 ? ((state.total - displaySec) / state.total) * 100 : 0

  useEffect(() => {
    if (state.running && displaySec === 0) {
      completeSession()
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [displaySec])

  const start = () => setState({ ...state, running: true, startedAt: Date.now() })
  const pause = () => setState({ ...state, running: false, startedAt: null, remaining: displaySec })

  const stop = async () => {
    const elapsedTotal = state.total - displaySec
    if (elapsedTotal >= 60) await saveSession(elapsedTotal)
    setState({ ...DEFAULT_STATE })
    toast.info(t('dw.stopped'))
  }

  async function completeSession() {
    await saveSession(state.total)
    setState({ ...DEFAULT_STATE })
    const modeLabel = state.mode === 'focus' ? t('dw.mode_focus') : state.mode === 'billable' ? t('dw.mode_billable') : t('dw.mode_break')
    toast.success(t('dw.session_complete', { mode: modeLabel }))
  }

  const saveSession = async (durationSec: number) => {
    const isBillable = state.mode === 'billable'
    const payload = {
      caseId: isBillable ? state.caseId : null,
      description: state.description || (state.mode === 'focus' ? t('dw.mode_focus') : isBillable ? t('dw.mode_billable') : t('dw.mode_break')),
      durationSec,
      billable: isBillable,
      hourlyRate: isBillable ? state.hourlyRate : null,
      sessionType: state.mode,
      date: new Date().toISOString(),
    }
    try {
      await fetch('/api/time-entries', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      })
      onChange()
    } catch {
      toast.error(t('dw.failed_save'))
    }
  }

  const setMode = (mode: 'focus' | 'billable' | 'break') => {
    const presets = { focus: 25 * 60, billable: 60 * 60, break: 5 * 60 }
    setState({ ...state, mode, total: presets[mode], remaining: presets[mode], running: false, startedAt: null })
  }

  const setDuration = (min: number) => {
    const sec = min * 60
    setState({ ...state, total: sec, remaining: sec, running: false, startedAt: null })
  }

  const todayStr = new Date().toDateString()
  const todayEntries = timeEntries.filter((t) => new Date(t.date).toDateString() === todayStr)
  const billableTodaySec = todayEntries.filter((e) => e.billable).reduce((s, e) => s + e.durationSec, 0)
  const focusTodaySec = todayEntries.filter((e) => !e.billable && e.sessionType === 'focus').reduce((s, e) => s + e.durationSec, 0)
  const billableTodaySAR = todayEntries.filter((e) => e.billable).reduce((s, e) => s + (e.durationSec / 3600) * (e.hourlyRate || 0), 0)
  const focusSessionsToday = todayEntries.filter((e) => e.sessionType === 'focus').length

  const weeklyChartData = useMemo(() => {
    const locale = lang === 'ar' ? 'ar-SA' : 'en-US'
    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date()
      d.setDate(d.getDate() - (6 - i))
      d.setHours(0, 0, 0, 0)
      const dayEntries = timeEntries.filter(
        (e) => new Date(e.date).toDateString() === d.toDateString()
      )
      const billable = dayEntries.filter((e) => e.billable).reduce((s, e) => s + e.durationSec / 3600, 0)
      const focus = dayEntries.filter((e) => !e.billable && e.sessionType === 'focus').reduce((s, e) => s + e.durationSec / 3600, 0)
      return {
        name: d.toLocaleDateString(locale, { weekday: 'short' }),
        [lang === 'ar' ? 'فوترة' : 'Billable']: Number(billable.toFixed(1)),
        [lang === 'ar' ? 'تركيز' : 'Focus']: Number(focus.toFixed(1)),
      }
    })
  }, [timeEntries, lang])

  const [chartMounted, setChartMounted] = useState(false)
  useEffect(() => { setChartMounted(true) }, [])

  const modeMeta = {
    focus: { label: t('dw.mode_focus'), icon: Brain, color: 'text-primary', ring: 'border-primary' },
    billable: { label: t('dw.mode_billable'), icon: DollarSign, color: 'text-emerald-600 dark:text-emerald-400', ring: 'border-emerald-500' },
    break: { label: t('dw.mode_break'), icon: Coffee, color: 'text-amber-600 dark:text-amber-400', ring: 'border-amber-500' },
  }
  const ModeIcon = modeMeta[state.mode].icon

  const circleRadius = 130
  const circleCircumference = 2 * Math.PI * circleRadius
  const strokeOffset = circleCircumference - (progressPct / 100) * circleCircumference

  // Format timer display in Arabic numerals when lang=ar
  const fmtTime = (sec: number) => {
    const h = Math.floor(sec / 3600)
    const m = Math.floor((sec % 3600) / 60)
    const s = sec % 60
    const pad = (n: number) => lang === 'ar' ? n.toLocaleString('ar-EG').padStart(2, '٠') : n.toString().padStart(2, '0')
    return `${pad(h)}:${pad(m)}:${pad(s)}`
  }

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold tracking-tight">{t('dw.title')}</h2>
        <p className="text-sm text-muted-foreground">{t('dw.subtitle')}</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Timer */}
        <Card className="lg:col-span-2">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-base font-semibold flex items-center gap-2">
                <TimerIcon className="h-4 w-4" />
                {t('dw.active_session')}
              </CardTitle>
              <Badge variant="outline" className={`${modeMeta[state.mode].color}`}>
                <ModeIcon className="h-3 w-3 mx-1" />
                {modeMeta[state.mode].label}
              </Badge>
            </div>
          </CardHeader>
          <CardContent>
            {/* Mode tabs */}
            <div className="grid grid-cols-3 gap-2 mb-6">
              {(['focus', 'billable', 'break'] as const).map((m) => {
                const Icon = modeMeta[m].icon
                return (
                  <button
                    key={m}
                    onClick={() => setMode(m)}
                    className={`rounded-lg border p-3 text-center transition-all ${
                      state.mode === m ? `${modeMeta[m].ring} bg-primary/5` : 'border-border hover:border-muted-foreground/30'
                    }`}
                  >
                    <Icon className={`h-4 w-4 mx-auto mb-1 ${state.mode === m ? modeMeta[m].color : 'text-muted-foreground'}`} />
                    <span className="text-xs font-medium">{modeMeta[m].label}</span>
                  </button>
                )
              })}
            </div>

            {/* Circular timer */}
            <div className="flex justify-center mb-6">
              <div className="relative">
                <svg width="300" height="300" viewBox="0 0 300 300" className="-rotate-90">
                  <circle cx="150" cy="150" r={circleRadius} fill="none" stroke="var(--muted)" strokeWidth="10" />
                  <circle
                    cx="150"
                    cy="150"
                    r={circleRadius}
                    fill="none"
                    stroke="var(--primary)"
                    strokeWidth="10"
                    strokeLinecap="round"
                    strokeDasharray={circleCircumference}
                    strokeDashoffset={strokeOffset}
                    style={{ transition: state.running ? 'stroke-dashoffset 0.25s linear' : 'none' }}
                  />
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <p className="text-5xl font-mono font-semibold tabular-nums" dir="ltr">
                    {fmtTime(displaySec)}
                  </p>
                  <p className="text-xs text-muted-foreground mt-2">
                    {state.running ? t('dw.in_progress') : t('dw.paused')}
                  </p>
                </div>
              </div>
            </div>

            {/* Duration presets */}
            <div className="flex justify-center gap-2 mb-6 flex-wrap">
              {[15, 25, 45, 60, 90].map((min) => (
                <Button
                  key={min}
                  variant={state.total === min * 60 ? 'default' : 'outline'}
                  size="sm"
                  className="h-7 text-xs"
                  disabled={state.running}
                  onClick={() => setDuration(min)}
                >
                  {lang === 'ar' ? min.toLocaleString('ar-EG') : min}{lang === 'ar' ? 'د' : 'm'}
                </Button>
              ))}
            </div>

            {/* Session metadata */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mb-4">
              <div className="space-y-1.5">
                <Label htmlFor="t-desc" className="text-xs">{t('dw.what_working')}</Label>
                <Input
                  id="t-desc"
                  value={state.description}
                  onChange={(e) => setState({ ...state, description: e.target.value })}
                  placeholder={t('dw.what_ph')}
                  disabled={state.running}
                />
              </div>
              {state.mode === 'billable' && (
                <>
                  <div className="space-y-1.5">
                    <Label htmlFor="t-case" className="text-xs">{t('dw.bill_to_case')}</Label>
                    <Select
                      value={state.caseId || ''}
                      onValueChange={(v) => setState({ ...state, caseId: v })}
                      disabled={state.running}
                    >
                      <SelectTrigger id="t-case"><SelectValue placeholder={t('dw.select_case')} /></SelectTrigger>
                      <SelectContent>
                        {cases.filter((c) => c.stage !== 'closed').map((c) => (
                          <SelectItem key={c.id} value={c.id}>{c.title}</SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-1.5">
                    <Label htmlFor="t-rate" className="text-xs">{t('dw.hourly_rate')}</Label>
                    <Input
                      id="t-rate"
                      type="number"
                      value={state.hourlyRate}
                      onChange={(e) => setState({ ...state, hourlyRate: parseFloat(e.target.value) || 0 })}
                      disabled={state.running}
                    />
                  </div>
                </>
              )}
            </div>

            {/* Controls */}
            <div className="flex justify-center gap-2">
              {!state.running ? (
                <Button size="lg" onClick={start} className="min-w-32">
                  <Play className="mx-1.5 h-4 w-4" /> {t('dw.start')}
                </Button>
              ) : (
                <Button size="lg" variant="outline" onClick={pause} className="min-w-32">
                  <Pause className="mx-1.5 h-4 w-4" /> {t('dw.pause')}
                </Button>
              )}
              <Button size="lg" variant="destructive" onClick={stop} disabled={!state.running && state.remaining === state.total}>
                <Square className="mx-1.5 h-4 w-4" /> {t('dw.stop_save')}
              </Button>
            </div>
          </CardContent>
        </Card>

        {/* Today's stats */}
        <div className="space-y-4">
          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold flex items-center gap-2">
                <TrendingUp className="h-4 w-4 text-primary" /> {t('dw.today')}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <Stat label={t('dw.billable_hours')} value={formatDuration(billableTodaySec, lang)} icon={<Clock className="h-3.5 w-3.5" />} />
              <Stat label={t('dw.focus_time')} value={formatDuration(focusTodaySec, lang)} icon={<Brain className="h-3.5 w-3.5" />} />
              <Stat label={t('dw.focus_sessions')} value={focusSessionsToday.toLocaleString('ar-EG')} icon={<TimerIcon className="h-3.5 w-3.5" />} />
              <Separator />
              <div className="pt-1">
                <p className="text-xs text-muted-foreground mb-1">{t('dw.billable_revenue')}</p>
                <p className="text-2xl font-semibold text-emerald-700 dark:text-emerald-300">{formatSAR(billableTodaySAR, lang)}</p>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-sm font-semibold flex items-center gap-2">
                <History className="h-4 w-4" /> {t('dw.recent_sessions')}
              </CardTitle>
            </CardHeader>
            <CardContent>
              <ScrollArea className="h-[280px] px-2 scroll-thin">
                <div className="space-y-2">
                  {timeEntries.slice(0, 15).map((e) => (
                    <div key={e.id} className="rounded-md border border-border p-2.5">
                      <div className="flex items-center justify-between gap-2 mb-1">
                        <p className="text-xs font-medium truncate flex-1">{e.description}</p>
                        <span className="text-xs font-mono" dir="ltr">{formatDuration(e.durationSec, lang)}</span>
                      </div>
                      <div className="flex items-center justify-between gap-2">
                        <Badge
                          variant="outline"
                          className={`text-[10px] px-1.5 py-0 ${
                            e.sessionType === 'billable' ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-300' :
                            e.sessionType === 'focus' ? 'bg-primary/10 text-primary' :
                            'bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-300'
                          }`}
                        >
                          {t(`session.${e.sessionType}`)}
                        </Badge>
                        <span className="text-[10px] text-muted-foreground">{formatDate(e.date, lang)}</span>
                      </div>
                      {e.billable && e.hourlyRate && (
                        <p className="text-[10px] text-emerald-700 dark:text-emerald-300 mt-1 font-medium">
                          {formatSAR((e.durationSec / 3600) * e.hourlyRate, lang)}
                        </p>
                      )}
                    </div>
                  ))}
                  {timeEntries.length === 0 && (
                    <p className="text-xs text-muted-foreground text-center py-8">{t('dw.no_sessions')}</p>
                  )}
                </div>
              </ScrollArea>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Weekly hours chart */}
      {chartMounted && (
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-semibold flex items-center gap-2">
              <BarChart2 className="h-4 w-4 text-primary" />
              {lang === 'ar' ? 'ساعات الأسبوع الماضي' : 'Last 7 Days — Hours Breakdown'}
            </CardTitle>
          </CardHeader>
          <CardContent className="h-52 pt-2">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={weeklyChartData} margin={{ top: 8, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} opacity={0.3} />
                <XAxis dataKey="name" stroke="#888888" fontSize={11} tickLine={false} axisLine={false} />
                <YAxis stroke="#888888" fontSize={11} tickLine={false} axisLine={false} unit="h" />
                <Tooltip
                  contentStyle={{
                    background: 'var(--card)',
                    borderColor: 'var(--border)',
                    borderRadius: '8px',
                    fontSize: '12px',
                  }}
                />
                <Legend verticalAlign="top" height={28} iconType="circle" wrapperStyle={{ fontSize: '11px' }} />
                <Bar dataKey={lang === 'ar' ? 'فوترة' : 'Billable'} stackId="a" fill="oklch(0.42 0.09 160)" radius={[0, 0, 0, 0]} />
                <Bar dataKey={lang === 'ar' ? 'تركيز' : 'Focus'} stackId="a" fill="oklch(0.7 0.13 160)" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>
      )}
    </div>
  )
}

function Stat({ label, value, icon }: { label: string; value: string; icon: React.ReactNode }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-xs text-muted-foreground flex items-center gap-1.5">{icon}{label}</span>
      <span className="text-sm font-mono font-medium" dir="ltr">{value}</span>
    </div>
  )
}

"use client"

import * as React from "react"
import useEmblaCarousel, {
  type UseEmblaCarouselType,
} from "embla-carousel-react"
import { ArrowLeft, ArrowRight } from "lucide-react"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"

type CarouselApi = UseEmblaCarouselType[1]
type UseCarouselParameters = Parameters<typeof useEmblaCarousel>
type CarouselOptions = UseCarouselParameters[0]
type CarouselPlugin = UseCarouselParameters[1]

type CarouselProps = {
  opts?: CarouselOptions
  plugins?: CarouselPlugin
  orientation?: "horizontal" | "vertical"
  setApi?: (api: CarouselApi) => void
}

type CarouselContextProps = {
  carouselRef: ReturnType<typeof useEmblaCarousel>[0]
  api: ReturnType<typeof useEmblaCarousel>[1]
  scrollPrev: () => void
  scrollNext: () => void
  canScrollPrev: boolean
  canScrollNext: boolean
} & CarouselProps

const CarouselContext = React.createContext<CarouselContextProps | null>(null)

function useCarousel() {
  const context = React.useContext(CarouselContext)

  if (!context) {
    throw new Error("useCarousel must be used within a <Carousel />")
  }

  return context
}

function Carousel({
  orientation = "horizontal",
  opts,
  setApi,
  plugins,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & CarouselProps) {
  const [carouselRef, api] = useEmblaCarousel(
    {
      ...opts,
      axis: orientation === "horizontal" ? "x" : "y",
    },
    plugins
  )
  const [canScrollPrev, setCanScrollPrev] = React.useState(false)
  const [canScrollNext, setCanScrollNext] = React.useState(false)

  const onSelect = React.useCallback((api: CarouselApi) => {
    if (!api) return
    setCanScrollPrev(api.canScrollPrev())
    setCanScrollNext(api.canScrollNext())
  }, [])

  const scrollPrev = React.useCallback(() => {
    api?.scrollPrev()
  }, [api])

  const scrollNext = React.useCallback(() => {
    api?.scrollNext()
  }, [api])

  const handleKeyDown = React.useCallback(
    (event: React.KeyboardEvent<HTMLDivElement>) => {
      if (event.key === "ArrowLeft") {
        event.preventDefault()
        scrollPrev()
      } else if (event.key === "ArrowRight") {
        event.preventDefault()
        scrollNext()
      }
    },
    [scrollPrev, scrollNext]
  )

  React.useEffect(() => {
    if (!api || !setApi) return
    setApi(api)
  }, [api, setApi])

  React.useEffect(() => {
    if (!api) return
    onSelect(api)
    api.on("reInit", onSelect)
    api.on("select", onSelect)

    return () => {
      api?.off("select", onSelect)
    }
  }, [api, onSelect])

  return (
    <CarouselContext.Provider
      value={{
        carouselRef,
        api: api,
        opts,
        orientation:
          orientation || (opts?.axis === "y" ? "vertical" : "horizontal"),
        scrollPrev,
        scrollNext,
        canScrollPrev,
        canScrollNext,
      }}
    >
      <div
        onKeyDownCapture={handleKeyDown}
        className={cn("relative", className)}
        role="region"
        aria-roledescription="carousel"
        data-slot="carousel"
        {...props}
      >
        {children}
      </div>
    </CarouselContext.Provider>
  )
}

function CarouselContent({ className, ...props }: React.ComponentProps<"div">) {
  const { carouselRef, orientation } = useCarousel()

  return (
    <div
      ref={carouselRef}
      className="overflow-hidden"
      data-slot="carousel-content"
    >
      <div
        className={cn(
          "flex",
          orientation === "horizontal" ? "-ms-4" : "-mt-4 flex-col",
          className
        )}
        {...props}
      />
    </div>
  )
}

function CarouselItem({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useCarousel()

  return (
    <div
      role="group"
      aria-roledescription="slide"
      data-slot="carousel-item"
      className={cn(
        "min-w-0 shrink-0 grow-0 basis-full",
        orientation === "horizontal" ? "ps-4" : "pt-4",
        className
      )}
      {...props}
    />
  )
}

function CarouselPrevious({
  className,
  variant = "outline",
  size = "icon",
  ...props
}: React.ComponentProps<typeof Button>) {
  const { orientation, scrollPrev, canScrollPrev } = useCarousel()

  return (
    <Button
      data-slot="carousel-previous"
      variant={variant}
      size={size}
      className={cn(
        "absolute size-8 rounded-full",
        orientation === "horizontal"
          ? "top-1/2 -start-12 -translate-y-1/2"
          : "-top-12 start-1/2 -translate-x-1/2 rotate-90",
        className
      )}
      disabled={!canScrollPrev}
      onClick={scrollPrev}
      {...props}
    >
      <ArrowLeft />
      <span className="sr-only">Previous slide</span>
    </Button>
  )
}

function CarouselNext({
  className,
  variant = "outline",
  size = "icon",
  ...props
}: React.ComponentProps<typeof Button>) {
  const { orientation, scrollNext, canScrollNext } = useCarousel()

  return (
    <Button
      data-slot="carousel-next"
      variant={variant}
      size={size}
      className={cn(
        "absolute size-8 rounded-full",
        orientation === "horizontal"
          ? "top-1/2 -end-12 -translate-y-1/2"
          : "-bottom-12 start-1/2 -translate-x-1/2 rotate-90",
        className
      )}
      disabled={!canScrollNext}
      onClick={scrollNext}
      {...props}
    >
      <ArrowRight />
      <span className="sr-only">Next slide</span>
    </Button>
  )
}

export {
  type CarouselApi,
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselPrevious,
  CarouselNext,
}

import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}
